def parseXml(xmlStr: String): Option[String] = {
  val xml = XML.loadString(xmlStr)
  // Add your parsing logic here to extract settings from the XML.
  // This example assumes a single "settings" element with nested attribute-value pairs.
  (xml \ "settings").headOption match {
    case Some(settingsNode) => settingsNode.attribute("name").text ++ ": " + settingsNode.text
    case None               => None
  }
